com.mirth.connect.plugins.javascriptstep.script:
var mapping;

try {
	mapping = msg['PID']['PID.2'].(function(){return (new XML(this))['PID.2.5'] == 'PAS'}())['PID.2.1'].toString(); 
} catch (e) {
	logger.error('HospitalNumber: ' + e);
	mapping = '';
}

channelMap.put('HospitalNumber', validate( mapping , '', new Array()));

var mapping;

try {
	var datetime = msg['PV2']['PV2.8']['PV2.8.1'].toString();

     if (datetime == '') {
     	datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();
     }

	mapping = datetime.substring(0, 4) + '-' + datetime.substring(4, 6) + '-' + datetime.substring(6, 8);
} catch (e) {
	logger.error('VisitDate: ' + e);
	mapping = '';
}

channelMap.put('VisitDate', validate(mapping, '', new Array()));

var mapping;

try {
	var datetime = msg['PV2']['PV2.8']['PV2.8.1'].toString();

     if (datetime == '') {
     	datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();
     }

	mapping = datetime.substring(8, 10) + ':' + datetime.substring(10, 12);
} catch (e) {
	logger.error('VisitTime: ' + e);
	mapping = '';
}

channelMap.put('VisitTime', validate(mapping, '', new Array()));

var mapping;

try {
     mapping = msg['PV1']['PV1.3']['PV1.3.1'].toString();

     if (msg['MSH']['MSH.9']['MSH.9.2'].toString() == 'A12') {
		mapping = msg['PV1']['PV1.6']['PV1.6.1'].toString();
	}

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('ClinicCode', validate(mapping, '', new Array()));

var mapping;

try {
	if (msg['PV1']['PV1.9']['PV1.9.2'] != undefined) {
		mapping = msg['PV1']['PV1.9']['PV1.9.2'].toString();

	} else if (msg['PV1']['PV1.9']['PV1.9.1'] != undefined) {
		mapping = msg['PV1']['PV1.9']['PV1.9.1'].toString();

	} else {
		mapping = 'Unknown';
	}

} catch (e) {
	logger.error('DoctorCode: ' + e);
	mapping = '';
}

channelMap.put('DoctorCode', validate(mapping, '', new Array()));

var mapping;

try {
	var eventtime = msg['EVN']['EVN.2']['EVN.2.1'].toString();

	var admittime = msg['PV1']['PV1.44']['PV1.44.1'].toString();

	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();

	var dna = msg['PV2']['PV2.24']['PV2.24.1'].toString();

	var dis = msg['PV2']['PV2.27']['PV2.27.1'].toString();

	var prior = msg['PV1']['PV1.6']['PV1.6.1'].toString();

	var visitstatus = 'Scheduled';

	if (dna == 'DNA') {
		visitstatus = 'Did Not Attend';

	} else if (messagetype == 'A02' || (messagetype == 'A08' && prior != '')) {
		visitstatus = 'Transferred to ' + msg['PV1']['PV1.3']['PV1.3.9'].toString();

	} else if (messagetype == 'A08' || dis != '') {
		visitstatus = 'Departed ' + eventtime.substring(8, 10) + ':' + eventtime.substring(10, 12);

	} else if (messagetype == 'A01') {
		visitstatus = 'Arrived ' + eventtime.substring(8, 10) + ':' + eventtime.substring(10, 12);

	} else if (messagetype == 'A13' || messagetype == 'A12') {
		visitstatus = 'Arrived ' + admittime.substring(8, 10) + ':' + admittime.substring(10, 12);

	} else if (messagetype == 'A03') {
		visitstatus = 'Discharged ' + eventtime.substring(8, 10) + ':' + eventtime.substring(10, 12);
	}

     mapping = '<AppointmentMapping><Key>Status</Key><Value>' + visitstatus + '</Value></AppointmentMapping>';

     //if (messagetype == 'A08' && dna != 'DNA' && dis == '' && prior == '') {
	//	mapping = '';
	//}

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitStatusXML', validate(mapping, '', new Array()));

var mapping;

try {
	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();
	mapping = '0'; //(messagetype == 'A08') ? '1' : '0';
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('PartialRecord', validate(mapping, '', new Array()));

var mapping;

try {
	mapping = msg['PID']['PID.3'].(function(){return (new XML(this))['PID.3.5'] == 'NHS'}())['PID.3.1'].toString(); 
} catch (e) {
	logger.error('NHSNumber: ' + e);
	mapping = '';
}

channelMap.put('NHSNumber',  mapping );

var mapping;

try {
	mapping = msg['MRG']['MRG.1'].(function(){return (new XML(this))['MRG.1.5'] == 'FACIL'}())['MRG.1.1'].toString(); 
} catch (e) {
	logger.error('Secondary HospitalNumber: ' + e);
	mapping = '';
}

channelMap.put('SecondaryHospitalNumber', validate( mapping , '', new Array()));

var responseStr = response.getMessage().toString();

if (responseStr.indexOf("<!-- start log messages -->") != -1) {
	responseStr = responseStr.substr(0, responseStr.indexOf("<!-- start log messages -->"));
}

var ResponseXML = new XML(responseStr);

for each (var w in ResponseXML.Warnings.children()) {
	if (w.toString().indexOf("Could not find GP") == -1 && w.toString().indexOf("Could not find Practice") == -1)	{
		responseStatus = ERROR;

		if (responseErrorMessage == null) {
			responseErrorMessage = w.toString();
		} else {
			responseErrorMessage += "\n" + w.toString();
		}
	}
}

var responseStr = response.getMessage().toString();

if (responseStr.indexOf("<!-- start log messages -->") != -1) {
	responseStr = responseStr.substr(0, responseStr.indexOf("<!-- start log messages -->"));
}

var ResponseXML = new XML(responseStr);

channelMap.put('PatientId', validate( ResponseXML.Id.toString() , '', new Array()));

var mapping;

try {
	mapping = msg['PID']['PID.3'].(function() { return (new XML(this))['PID.3.5'] == 'FACIL'; }())['PID.3.1'].toString();
} catch (e) {
	logger.error('HospitalNumber: ' + e);
	mapping = '';
}

channelMap.put('HospitalNumber', validate( mapping , '', new Array()));

var mapping;

try {
	mapping = msg['PV1']['PV1.19']['PV1.19.1'].toString() + "_" + msg['PV1']['PV1.19']['PV1.19.4'].toString(); 
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitID', validate( mapping , '', new Array()));

var mapping;

try {
	var datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();
	mapping = datetime.substring(0, 4) + '-' + datetime.substring(4, 6) + '-' + datetime.substring(6, 8);
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitDate', validate(mapping, '', new Array()));

var mapping;

try {
	var datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();
	mapping = datetime.substring(8, 10) + ':' + datetime.substring(10, 12);
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitTime', validate(mapping, '', new Array()));

var mapping;

try {
	var eventtime = msg['EVN']['EVN.2']['EVN.2.1'].toString();

	var admittime = msg['PV1']['PV1.44']['PV1.44.1'].toString();

	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();

	var dna = msg['PV1']['PV1.14']['PV1.14.1'].toString();

	var dis = msg['PV2']['PV2.27']['PV2.27.1'].toString();

	var prior = msg['PV1']['PV1.6']['PV1.6.1'].toString();

	var statuscode = msg['PV1']['PV1.14']['PV1.14.1'].toString();

	var visitstatus = 'Scheduled';

	if (dna == 'DNA') {
		visitstatus = 'Did Not Attend';

	} else if (messagetype == 'A02' || (messagetype == 'A08' && prior != '')) {
		visitstatus = 'Transferred to ' + msg['PV1']['PV1.3']['PV1.3.9'].toString();

	} else if (messagetype == 'A08' || dis != '') {
		visitstatus = 'Departed ' + eventtime.substring(8, 10) + ':' + eventtime.substring(10, 12);

	} else if (messagetype == 'A01') {
		visitstatus = 'Attended';

	} else if (messagetype == 'A13' || messagetype == 'A12') {
		visitstatus = 'Arrived ' + admittime.substring(8, 10) + ':' + admittime.substring(10, 12);

	} else if (messagetype == 'A03') {
		visitstatus = 'Discharged ' + eventtime.substring(8, 10) + ':' + eventtime.substring(10, 12);

	} else if (messagetype == 'A04') {
		visitstatus = 'Attended';
	}


     mapping = '<AppointmentMapping><Key>Status</Key><Value>' + visitstatus + '</Value></AppointmentMapping>';

	/* if (messagetype == 'A08') {
		mapping = '';
	} */

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitStatusXML', validate(mapping, '', new Array()));

var mapping;

try {
	var cliniccode = msg['PV1']['PV1.3']['PV1.3.1'].toString();

	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();

	var procedure = msg['PR1']['PR1.3']['PR1.3.2'].toString();

	procedure = procedure.replace('</PR1.3.2><PR1.3.2>', '; ');
	procedure = procedure.replace('<PR1.3.2>', '');
	procedure = procedure.replace('</PR1.3.2>', '');

     if (cliniccode == 'H2' && messagetype == 'A05') {
     	if (procedure == '') {
     		procedure = 'Unknown';
     	} else if (procedure == 'Injection into vitreous body NEC') {
     		procedure = 'Intravitreal injection';
     	} else if (   procedure == 'Phacoemulsification of lens; Insertion of prosthetic replacement for lens NEC'
     	           || procedure == 'Insertion of prosthetic replacement for lens NEC; Phacoemulsification of lens'
     	          ) {
     	     procedure = 'Phaco + IOL';
     	}

     	mapping = '<AppointmentMapping><Key>Procedure' + ((procedure.indexOf('njection') > -1) ? 'Injection' : '') + '</Key><Value>' + procedure + '</Value></AppointmentMapping>';
     }
     else {
     	mapping = '';
     }

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('ProcedureXML', validate(mapping, '', new Array()));

var mapping;

try {
	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();
	mapping = (messagetype == 'A08') ? '1' : '0';
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('PartialRecord', validate(mapping, '', new Array()));

var mapping;

try {
	mapping = msg['PV1']['PV1.3']['PV1.3.2'].toString();

	if (mapping == '') {
		mapping = msg['PV1']['PV1.3']['PV1.3.1'].toString();
	}

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('SessionCode', validate( mapping , '', new Array()));

var responseStr = response.getMessage().toString();

if (responseStr.indexOf("<!-- start log messages -->") != -1) {
	responseStr = responseStr.substr(0, responseStr.indexOf("<!-- start log messages -->"));
}

var ResponseXML = new XML(responseStr);

for each (var w in ResponseXML.Warnings.children()) {
	if (w.toString().indexOf("Could not find GP") == -1 && w.toString().indexOf("Could not find Practice") == -1)	{
		responseStatus = ERROR;

		if (responseErrorMessage == null) {
			responseErrorMessage = w.toString();
		} else {
			responseErrorMessage += "\n" + w.toString();
		}
	}
}

var responseStr = response.getMessage().toString();

if (responseStr.indexOf("<!-- start log messages -->") != -1) {
	responseStr = responseStr.substr(0, responseStr.indexOf("<!-- start log messages -->"));
}

var ResponseXML = new XML(responseStr);

channelMap.put('PatientId', validate( ResponseXML.Id.toString() , '', new Array()));

com.mirth.connect.plugins.javascriptrule.script:
if ($('d1').getStatus() != Status.SENT)
{
	return false;
}

if (   msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A01"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A05"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A08"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A11"
   )
{
	if ($('ClinicCode') == "ECAS")
	{
		return false;
	}

	if (   msg['MSH']['MSH.9']['MSH.9.2'].toString() != "A05"
	    && $('ClinicCode') == "H2"
	   )
	{
		return false;
	}

	return true;
}

return false;

if ($('d1').getStatus() != Status.SENT)
{
	return false;
}

if (   msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A38")
{
	if ($('ClinicCode') == "ECAS")
	{
		return false;
	}

	if (   msg['MSH']['MSH.9']['MSH.9.2'].toString() != "A38"
	    && $('ClinicCode') == "H2"
	   )
	{
		return false;
	}

	return true;
}

return false;

if ( 
    msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A05"
    && msg['PV1']['PV1.14']['PV1.14.1'].toString() == 'DNA'
   )
{	
	return true;
}

return false;

var bookingType = channelMap.get('BookingType');

if(bookingType.toLocaleLowerCase().includes('cataract')
     || bookingType.toLocaleLowerCase().includes('glaucoma')
	|| bookingType.toLocaleLowerCase().includes('oculoplastics')
	|| bookingType.toLocaleLowerCase().includes('yag')
	|| bookingType.toLocaleLowerCase().includes('laser - slt')
) {
	return true;
} else {
	return false;
}

channel.postprocessingScript:
